export type OrderStatus =
  | "draft"
  | "confirmed"
  | "in_production"
  | "quality_check"
  | "packed"
  | "shipped"
  | "delivered"
  | "completed"
  | "cancelled";

export type OrderPaymentStatus =
  | "pending"
  | "advance_received"
  | "partially_paid"
  | "fully_paid"
  | "refunded";

export type RecipientDeliveryStatus =
  | "pending"
  | "in_production"
  | "packed"
  | "shipped"
  | "delivered"
  | "returned";

