/**
 * Converts an accepted quote into a draft order. Quotes are not linked to a
 * company directly (they store a free-text client company), so the company is
 * resolved by name match, or supplied explicitly via `companyId`.
 */
export async function convertQuoteToOrder(
  quoteId: string,
  companyId?: string,
  createdBy?: string,
): Promise<Order> {
  const supa = await userDb();
  const { data: quote, error } = await supa
    .from("quotes")
    .select("*")
    .eq("id", quoteId)
    .maybeSingle();
  if (error) throw new Error(`Convert quote failed: ${error.message}`);
  if (!quote) throw new Error("Quote not found");

  // Resolve the company.
  let resolvedCompanyId = companyId ?? null;
  if (!resolvedCompanyId && quote.client_company) {
    const { data: match } = await supa
      .from("companies")
      .select("id")
      .ilike("name", quote.client_company as string)
      .maybeSingle();
    resolvedCompanyId = (match?.id as string) ?? null;
  }
  if (!resolvedCompanyId) {
    throw new Error(
      "Could not resolve a company for this quote. Pass companyId explicitly.",
    );
  }

  const products: OrderProductInput[] = (
    (quote.products as Array<{ sku: string; quantity: number }> | null) ?? []
  ).map((p) => ({ sku: p.sku, quantity: p.quantity }));

  const order = await createOrder(
    {
      companyId: resolvedCompanyId,
      quoteId: quote.id as string,
      occasionKey: (quote.occasion_key as string | null) ?? null,
      occasionLabel: (quote.occasion as string) ?? undefined,
      occasionType: (quote.occasion as string) ?? undefined,
      products,
      packagingTier: (quote.packaging_tier as PackagingTierId) ?? "standard",
      personalisationLevel:
        (quote.personalisation_level as PersonalisationLevelId) ??
        "name_occasion",
      kitCount: Number(quote.kit_count ?? quote.quantity ?? 1),
      isRush: Boolean(quote.rush_order),
      rushDays: (quote.rush_days as number | null) ?? undefined,
      discountPercent: Number(quote.discount_percent ?? 0),
      specialInstructions: (quote.special_instructions as string) ?? undefined,
    },
    createdBy,
  );

  // Mark the quote accepted/converted.
  await supa
    .from("quotes")
    .update({ status: "accepted", accepted_at: new Date().toISOString() })
    .eq("id", quoteId);

  // Prompt 7a: a converted quote = a committed gift. Persist occasion_gift_state (status ordered
  // + order_id) so the cancel-reversal never clears it. Only relevant for occasion-linked quotes.
  if (quote.occasion_key) {
    try {
      const { createAdminClient } = await import("@/lib/supabase/admin");
      const { markGiftOrderedForQuote } = await import("@/lib/engines/notifications");
      await markGiftOrderedForQuote(createAdminClient(), quoteId, order.id);
    } catch (e) {
      console.error("[convertQuoteToOrder] gift-state persist failed:", e);
    }
  }

  return order;
}

// ---------------------------------------------------------------------------
// Gift record generation (on delivery)
// ---------------------------------------------------------------------------

/**
 * For each recipient with a linked employee, create one gift_record per line
 * item, link it back to the order, and bump employee_preferences counters.
 * Idempotent at the recipient level - recipients already linked to a gift
 * record are skipped.
 */
export async function generateGiftRecords(
  orderId: string,
): Promise<{ created: number; errors: string[] }> {
  const supa = await userDb();
  const errors: string[] = [];

  const order = await getOrder(orderId);
  if (!order) return { created: 0, errors: ["Order not found"] };

  const giftedDate =
    order.actual_delivery_date ?? new Date().toISOString().slice(0, 10);
  let created = 0;

  for (const recipient of order.recipients) {
    if (!recipient.employee_id) continue; // snapshot-only recipient
    if (recipient.gift_record_id) continue; // already generated

    let lastGiftId: string | null = null;
    for (const item of order.items) {
      const { data, error } = await supa
        .from("gift_records")
        .insert({
          company_id: order.company_id,
          employee_id: recipient.employee_id,
          product_sku: item.product_sku,
          product_name: item.product_name,
          collection_code: item.collection_code,
          occasion_type: order.occasion_type ?? "custom",
          occasion_label: order.occasion_label,
          // Stable occasion key (7a pattern) so history answers "what did we give Priya AND for
          // which occasion" and joins order↔quote↔occasion by a regen-stable string.
          occasion_key: order.occasion_key,
          gifted_date: giftedDate,
          packaging_tier: order.packaging_tier,
          personalisation_level: order.personalisation_level,
          narrative_message: recipient.personalisation_message,
          engraving_text: recipient.personalisation_name,
          delivery_status: "delivered",
          delivered_date: giftedDate,
          delivery_address: order.delivery_address,
          tracking_number: recipient.tracking_number ?? order.tracking_number,
          unit_price: item.unit_price,
          order_id: order.id,
          quote_id: order.quote_id,
          created_by: order.created_by,
        })
        .select("id")
        .single();
      if (error) {
        errors.push(
          `Recipient ${recipient.recipient_name} / ${item.product_sku}: ${error.message}`,
        );
        continue;
      }
      created += 1;
      lastGiftId = data.id as string;

      // Bump the learned preference counters for this employee.
      await bumpPreferences(supa, order.company_id, recipient.employee_id, giftedDate);
    }

    // Mark the recipient delivered + link to a gift record.
    if (lastGiftId) {
      await supa
        .from("order_recipients")
        .update({
          delivery_status: "delivered",
          delivered_date: giftedDate,
          gift_record_id: lastGiftId,
        })
        .eq("id", recipient.id);
    }
  }

  return { created, errors };
}

/** Ensures an employee_preferences row exists and increments gift counters. */
async function bumpPreferences(
  supa: SupabaseClient,
  companyId: string,
  employeeId: string,
  giftedDate: string,
): Promise<void> {
  const { data: existing } = await supa
    .from("employee_preferences")
    .select("id, total_gifts_received")
    .eq("employee_id", employeeId)
    .maybeSingle();

  if (existing) {
    await supa
      .from("employee_preferences")
      .update({
        total_gifts_received: Number(existing.total_gifts_received ?? 0) + 1,
        last_gifted_date: giftedDate,
      })
      .eq("id", existing.id);
  } else {
    await supa.from("employee_preferences").insert({
      employee_id: employeeId,
      company_id: companyId,
      total_gifts_received: 1,
      last_gifted_date: giftedDate,
    });
  }
}

// ---------------------------------------------------------------------------
// Company employees (for recipient selection in the admin UI)
// ---------------------------------------------------------------------------

export interface OrderEmployeeOption {
  id: string;
  name: string;
  email: string | null;
  department: string | null;
}

export async function listCompanyEmployees(
  companyId: string,
): Promise<OrderEmployeeOption[]> {
  const supa = await userDb();
  const { data, error } = await supa
    .from("employees")
    .select("id, full_name, email, department")
    .eq("company_id", companyId)
    .eq("is_active", true)
    .order("full_name", { ascending: true });
  if (error) throw new Error(`List employees failed: ${error.message}`);
  return (data ?? []).map((e) => ({
    id: e.id as string,
    name: (e.full_name as string) ?? "Employee",
    email: (e.email as string) ?? null,
    department: (e.department as string) ?? null,
  }));
}

export interface CompanyOption {
  id: string;
  name: string;
}

export async function listCompaniesForOrders(): Promise<CompanyOption[]> {
  const supa = await userDb();
  const { data, error } = await supa
    .from("companies")
    .select("id, name")
    .order("name", { ascending: true });
  if (error) throw new Error(`List companies failed: ${error.message}`);
  return (data ?? []).map((c) => ({ id: c.id as string, name: c.name as string }));
}

// ---------------------------------------------------------------------------
// Stats
// ---------------------------------------------------------------------------

export interface OrderStats {
  total: number;
  byStatus: Record<string, number>;
  totalRevenue: number;
  avgOrderValue: number;
  thisMonth: number;
  lastMonth: number;
}

export async function getOrderStats(companyId?: string): Promise<OrderStats> {
  const supa = await userDb();
  let query = supa
    .from("orders")
    .select("status, grand_total, created_at");
  if (companyId) query = query.eq("company_id", companyId);
  const { data, error } = await query;
  if (error) throw new Error(`Order stats failed: ${error.message}`);

  const rows = data ?? [];
  const byStatus: Record<string, number> = {};
  let totalRevenue = 0;
  let revenueCount = 0;
  let thisMonth = 0;
  let lastMonth = 0;

  const now = new Date();
  const thisMonthKey = `${now.getFullYear()}-${now.getMonth()}`;
  const lastDate = new Date(now.getFullYear(), now.getMonth() - 1, 1);
  const lastMonthKey = `${lastDate.getFullYear()}-${lastDate.getMonth()}`;

  for (const r of rows) {
    const status = (r.status as string) ?? "draft";
    byStatus[status] = (byStatus[status] ?? 0) + 1;
    if (status !== "cancelled" && r.grand_total != null) {
      totalRevenue += Number(r.grand_total);
      revenueCount += 1;
    }
    const created = new Date(r.created_at as string);
    const key = `${created.getFullYear()}-${created.getMonth()}`;
    if (key === thisMonthKey) thisMonth += 1;
    if (key === lastMonthKey) lastMonth += 1;
  }

  return {
    total: rows.length,
    byStatus,
    totalRevenue,
    avgOrderValue: revenueCount > 0 ? Math.round(totalRevenue / revenueCount) : 0,
    thisMonth,
    lastMonth,
  };
}

// ---------------------------------------------------------------------------
// Client-facing projection (strips ALL financial + internal fields)
// ---------------------------------------------------------------------------

export interface ClientOrderItem {
  product_sku: string;
  product_name: string;
  collection_code: string | null;
  quantity: number;
}

export interface ClientOrderRecipient {
  recipient_name: string;
  recipient_department: string | null;
  personalisation_name: string;
  delivery_status: RecipientDeliveryStatus;
  delivered_date: string | null;
}

export interface ClientOrder {
  id: string;
  order_number: string | null;
  status: OrderStatus;
  occasion_type: string | null;
  occasion_label: string | null;
  kit_count: number;
  packaging_tier: string;
  expected_delivery_date: string | null;
  actual_delivery_date: string | null;
  tracking_number: string | null;
  courier_partner: string | null;
  client_notes: string | null;
  created_at: string;
  items: ClientOrderItem[];
  recipients: ClientOrderRecipient[];
  statusHistory: Array<{ to_status: string; created_at: string; notes: string | null }>;
}

/** Projects a full Order into the price-free shape sent to clients. */
export function toClientOrder(order: Order): ClientOrder {
  return {
    id: order.id,
    order_number: order.order_number,
    status: order.status,
    occasion_type: order.occasion_type,
    occasion_label: order.occasion_label,
    kit_count: order.kit_count,
    packaging_tier: order.packaging_tier,
    expected_delivery_date: order.expected_delivery_date,
    actual_delivery_date: order.actual_delivery_date,
    tracking_number: order.tracking_number,
    courier_partner: order.courier_partner,
    client_notes: order.client_notes,
    created_at: order.created_at,
    items: order.items.map((i) => ({
      product_sku: i.product_sku,
      product_name: i.product_name,
      collection_code: i.collection_code,
      quantity: i.quantity,
    })),
    recipients: order.recipients.map((r) => ({
      recipient_name: r.recipient_name,
      recipient_department: r.recipient_department,
      personalisation_name: r.personalisation_name,
      delivery_status: r.delivery_status,
      delivered_date: r.delivered_date,
    })),
    statusHistory: order.statusHistory.map((s) => ({
      to_status: s.to_status,
      created_at: s.created_at,
      notes: s.notes,
    })),
  };
}

// Request-scoped RLS client, imported dynamically so this server-only engine
// can be imported by client components (for its exported constants/types)
// without pulling `next/headers` into the client bundle.
async function userDb() {
  const { createClient } = await import("@/lib/supabase/server");
  return createClient();
}
